CREATE OR REPLACE FUNCTION public.claim_super_admin_bootstrap() RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_uid uuid := auth.uid(); v_exists boolean; BEGIN IF v_uid IS NULL THEN RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '28000'; END IF; SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE role = 'super_admin') INTO v_exists; IF v_exists THEN RAISE EXCEPTION 'super_admin_already_exists' USING ERRCODE = '42501'; END IF; INSERT INTO public.user_roles (user_id, role) VALUES (v_uid, 'super_admin') ON CONFLICT (user_id, role) DO NOTHING; RETURN jsonb_build_object('ok', true, 'user_id', v_uid); END; $$; REVOKE EXECUTE ON FUNCTION public.claim_super_admin_bootstrap() FROM PUBLIC, anon; GRANT EXECUTE ON FUNCTION public.claim_super_admin_bootstrap() TO authenticated;